SELECT CLOSING_STATUS
FROM CLOSING_DAY
WHERE CLOSING_YMD = #{ymd}

SELECT emp_no FROM ( SELECT e.emp_no, CASE e.emp_grade WHEN 5 THEN 1 WHEN 6 THEN 2 WHEN 4 THEN 3 WHEN 3 THEN 4 END AS priority FROM emp e WHERE e.dept_code = #{deptCode} AND e.emp_grade IN
#{g}
ORDER BY priority ASC ) WHERE ROWNUM = 1

SELECT e.emp_no FROM emp e WHERE e.dept_code = #{deptCode} AND e.emp_grade IN
#{g}
ORDER BY CASE e.emp_grade WHEN 5 THEN 1 WHEN 6 THEN 2 WHEN 4 THEN 3 WHEN 3 THEN 4 END ASC

