UPDATE orders
eapp_status = #{eapp_status}, appr_empno = #{appr_empno}, order_confirmed_date = #{order_confirmed_date}, approval_timestamp = #{approval_timestamp}, order_rejected_date = #{order_rejected_date}, order_cancelled_date = #{order_cancelled_date}, order_refuse = #{order_refuse}
WHERE order_code = #{order_code}

